var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐?! 그런 게 어딨어!","JPN":"はあ！？　そんなのおかしいだろ！","ENG":"What?! That's such a rip-off!","TWN":"什麼？！哪有這樣的！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"손님, 조심해 주세요. 손실이 나면 저희가 전액 변상해야……","JPN":"お客様、お気を付けください。壊れた際には私たちで全額弁償しないといけませんので……","ENG":"Ma'am, please. If it's damaged, then we'll have to pay out of our pocket–","TWN":"客人，麻煩小心一點，萬一有什麼損失，我們是要全額賠償……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"죄, 죄송합니다. 피곤해서 정신이 없다 보니 말실수를 했어요.","JPN":"も、も、申し訳ございません。疲れていたので、つい失言を。","ENG":"M-my apologies. I'm so tired and distracted that it just slipped out.","TWN":"抱…抱歉，是我太累說錯話。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아. 아냐. 나야말로 미안.","JPN":"い、いや。私こそごめん。","ENG":"No, don't worry about it. I should be the one apologizing to you.","TWN":"沒…沒有啦，我才對你不好意思。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하지만 도전장 한 장에 10만 헤이븐 코인이라니 너무하잖아.","JPN":"でも挑戦状1枚が10万ヘイブンコインなんてあんまりだ。","ENG":"But seriously? We have to pay 100k Haven Coins to enter the challenge?","TWN":"不過一張挑戰券竟然要10萬天堂幣，這是在搶劫嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시작부터 글렀네.","JPN":"最初からダメダメだね。","ENG":"Guess that's out of the picture.","TWN":"一開始就踢到鐵板呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"헤이븐 코인이 뭐야?","JPN":"ヘイブンコインってなに？","ENG":"What's a Haven Coin?","TWN":"天堂幣是什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤이븐 랜드에서 크레딧처럼 쓰는 거래 수단이야.","JPN":"ヘイブンランドでお金のように使われる取引手段だよ。","ENG":"It's money, like Credit, that's used in Havenland.","TWN":"是可以在天堂樂園中使用的一種交易貨幣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"10만이면 큰 액수이긴 해. 작은 집도 살 수 있을 정도로.","JPN":"10万といえば大金ではあるんだ。小さな家を一軒買えるくらいだから。","ENG":"And 100k is a lot of it. You could buy a small house with that amount.","TWN":"10萬是蠻多的，價值幾乎可以買下一間小套房。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오. 그렇구나.","JPN":"おお、そうなんだ。","ENG":"Ooh... I see.","TWN":"哇喔，原來是這樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠가 그랬어. 아빠처럼 청렴한 사람들은 자기 힘으로 돈을 버는 게 재미있대.","JPN":"パパがこう言ってたよ。パパのように正しい人たちは、自分の力でお金を稼ぐのが楽しいんだって。","ENG":"Here's what Daddy told me. Daddy said that people with integrity like him have fun making money on their own!","TWN":"爸爸說過，像爸爸那樣清廉的人，都認為靠自己的力量賺錢才有趣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"우리 다 같이 힘내서 10만 헤이븐 코인을 모아 보자! 분명 재밌을 거야!","JPN":"みんなで頑張って10万ヘイブンコインを集めてみようよ！　きっと面白いよ！","ENG":"So let's all work together and try to make 100k Haven Coins! It'll be fun!","TWN":"我們也一起努力賺到10萬天堂幣吧！一定會很有趣！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"맞아! 게임에 이기기만 하면 가지고 있는 헤이븐 코인을 잔뜩 늘릴 수 있으니까!","JPN":"そうだよ！　ゲームに勝ちさえすれば、手持ちのヘイブンコインをいっぱい増やせるから！","ENG":"She's right! You can earn a lot of coins by winning games here!","TWN":"沒錯！只要玩遊戲獲勝，我們手上的天堂幣一定會越來越多的！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"좋은 생각이긴 한데, 한 가지 치명적인 문제가 있어.","JPN":"いい考えではあるけど、一つだけクリティカルな問題がある。","ENG":"That's a good idea and all, but there's one critical problem.","TWN":"樂觀是很好，但現在有個致命的問題。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그게 뭔데?","JPN":"どんな？","ENG":"What's that?","TWN":"什麼問題？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리에게는 헤이븐 코인이 하나도 없거든.","JPN":"実はヘイブンコインが一枚もないんだ。","ENG":"We don't have a single Haven Coin left.","TWN":"我們根本連一個天堂幣都沒有。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"어어? 그럴 리가? 승선할 때 받지 않았어?","JPN":"ええ？　そんな！　乗船する時もらわなかった？","ENG":"H-huh? No way... Didn't you get some when you came on board the ship?","TWN":"蛤？真的假的？上船的時候沒拿到嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"사실 아까 시킨 음료수가 마지막이었어. 다들 놀러 온 기분으로 펑펑 썼으니 말이지.","JPN":"実はさっき頼んだ飲み物代で最後だったんだよ。みんな遊び気分でガンガン使っちゃったからさ。","ENG":"We used it all ordering drinks just a while ago. Everyone blew their money like they were on vacation or something.","TWN":"不瞞你說，剛剛買飲料花的天堂幣已經是最後僅有的，誰叫大家都一副出來玩的樣子，整個很敢花。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"미안해. 토토를 얌전히 시키려면 어쩔 수 없었는걸.","JPN":"ごめんね。トトを大人しくさせるためには仕方なかったの。","ENG":"I'm sorry. But it was the only way to keep Toto calm...","TWN":"對不起，要讓托托安靜的話就只能這樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"누, 누가 일이 이렇게 될 줄 알았냐.","JPN":"こ、こうなると思わなかったんだよ。","ENG":"W-we didn't know this would happen.","TWN":"誰…誰知道事情會變成這樣？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"하지만 판돈 없이 10만 헤이븐 코인을 버는 건 무리야.","JPN":"でも掛け金なしで10万ヘイブンコインを稼ぐのは無理。","ENG":"But with no coins, we can't make 100k Haven Coins.","TWN":"我們根本沒有賭本，怎麼可能賺到10萬天堂幣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하아, 지금 당장 그렇게 많은 돈을 어디서 구한대.","JPN":"はあ、あんな大金をどこで手に入れたらいいんだ？","ENG":"*Sigh* Where will we find that kind of money?","TWN":"哀，現在要去哪弄到那麼多的錢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……에휴, 모질이들. 이거나 받아.","JPN":"……まったく、頭の悪い子たちね。ほら。","ENG":"Ugh... I knew this would happen. Here you go.","TWN":"……哀哀，你們這群傻瓜，拿去吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응? 이게 뭐야?","JPN":"うん？　これは？","ENG":"Huh? What is it?","TWN":"嗯？這是什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"무슨 일이 있을지 모르니까 따로 헤이븐 코인을 교환해 뒀어.","JPN":"念のためにヘイブンコインを別に交換しておいたんだ。","ENG":"I exchanged some Haven Coins in case of emergency.","TWN":"我怕有什麼萬一，所以有另外換一些天堂幣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루랑 일하면서 모은 종잣돈인데……. 이거면 게임에 참가할 수 있을 거야.","JPN":"ルルと働きながら貯めたお金なんだけど……これならゲームに参加できるはずだよ。","ENG":"It's all the money I saved working with Lulu, but... It should be enough to participate in the game.","TWN":"這是我和露露工作存下來的資金……應該夠參加遊戲吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"괜찮겠어? 그렇게 소중한 자금을 덜컥 맡겨도?","JPN":"そんな大事なお金を私たちに任せちゃってもいいの？","ENG":"Are you sure? It's all your savings...","TWN":"確定嗎？你要把這麼珍貴的資金全交給我們嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 이대로 포기하면 위저드 출신 애들은 어떻게 해?","JPN":"じゃあ、このまま諦めたとしてウィザード出身の子どもたちはどうするの？","ENG":"What do you think will happen to all the Wizard kids here if we give up now?","TWN":"要不然呢？現在放棄的話，那巫師的孩子們該怎麼辦？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"미안한 척할 필요 없어. 너희들 뒤치다꺼리 하게 될 거라는 건 각오했으니까.","JPN":"悪く思う必要ないよ。アンタたちの面倒を見ることになるってことは覚悟してたから。","ENG":"There's no need to act sorry. I knew I'd be cleaning up after all of you the second I joined.","TWN":"不用裝作不好意思，我早就做好心理準備，會需要替你們善後。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"글린다…….","JPN":"グリンダ……","ENG":"Glinda...","TWN":"格琳達……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 훌륭해!","JPN":"おお、すばらしい！","ENG":"Ooh! Terrific!","TWN":"哇喔，你好優秀喔！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"친구랑 보물을 나눠 가지는 착한 아이는 시그마 해적단의 부선장으로 임명한다!","JPN":"友達とお宝を共有するいい子は、シグマ海賊団の副船長に任命する！","ENG":"Since you shared your treasure with your friends, I'm going to appoint you as co-captain of the Sigma Pirates!","TWN":"我要任命有好東西會和好朋友分享的人，當西格瑪海盜團的副船長！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"됐으니까 쪽박이나 찼단 봐. 루루에게 말해서 가만 안 놔둘 테니까.","JPN":"それはいいからちゃんと稼いでよね。じゃないと、ルルに話して痛い目に合わすよ。","ENG":"Whatever. Just don't lose it all, or I'm telling Lulu and she'll give you nightmares.","TWN":"不必，就當我是盤子吧，這件事不能跟露露說。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"엣헴. 걱정 마시라. 보드 게임은 내가 우리 회사 히든 보스라구.","JPN":"えっへん。ご心配なく。ボードゲームは私がうちの会社の隠れボスなんだから。","ENG":"Ahem. Don't worry. I'm the hidden boss of board games at our company!","TWN":"嘿嘿，放心吧，我可是我們公司的桌遊大師喔！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"어떻게 할 건데?","JPN":"どうするつもり？","ENG":"So, what's the plan?","TWN":"要怎麼做？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으음… 그러니까아… 수아랑 내가……","JPN":"うーん……えーっと……コトリと私が……","ENG":"Um... Well... Skia and I will...","TWN":"嗯…就是呢…蘇亞和我……"},"stage":{"bg":"CLUB1","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};